// 1. TRAEMOS LOS ÍTEMS (PRODUCTOS) Y EL DESCUENTO DEL WEBHOOK
const itemsEntrada = $('Recibo Datos').all(); 

// --- RESCATE DEL DESCUENTO ---
let montoDescuento = 0;
try {
    const webhookData = $('Webhook').first().json.body; 
    montoDescuento = parseFloat(webhookData.discountAmount || 0);
} catch (e) {
    montoDescuento = 0;
}

// Tomamos cabecera del primero
const cabecera = itemsEntrada[0].json;

// --- MEJORA: Detección flexible de tipo de comprobante ---
const tipoOriginal = (cabecera.type || cabecera.TipoDeFactura || "").toString().toUpperCase();

let codigoAfip = 11; // Por defecto C

if (tipoOriginal.includes("A")) {
    codigoAfip = tipoOriginal.includes("NOTA") ? 3 : 1;
} else if (tipoOriginal.includes("B")) {
    codigoAfip = tipoOriginal.includes("NOTA") ? 8 : 6;
} else if (tipoOriginal.includes("C")) {
    codigoAfip = tipoOriginal.includes("NOTA") ? 13 : 11;
}

// 3. INICIALIZAMOS VARIABLES
let totalNeto = 0;
let totalIva = 0;
let totalComprobante = 0;
let detalleItemsParaAfip = [];

// 4. BUCLE DE PRODUCTOS
for (const item of itemsEntrada) {
    const prod = item.json;

    const cantidad = parseFloat(prod.Cantidad || 0);
    const precioUnitario = parseFloat(prod.PrecioUnitario || 0);
    const netoLinea = parseFloat((precioUnitario * cantidad).toFixed(2));

    // --- MEJORA IVA: Forzamos ID 5 si es comprobante tipo 1, 3, 6 u 8 ---
    let tasaIva = 0; 
    let idAlicuota = 3; 

    // Si el código es de los que llevan IVA (A o B), forzamos ID 5
    if ([1, 3, 6, 8].includes(codigoAfip)) { 
        tasaIva = 0.21; 
        idAlicuota = 5; 
    }

    const ivaLinea = parseFloat((netoLinea * tasaIva).toFixed(2));
    const totalLinea = parseFloat((netoLinea + ivaLinea).toFixed(2));

    totalNeto += netoLinea;
    totalIva += ivaLinea;
    totalComprobante += totalLinea;

    detalleItemsParaAfip.push({
        "Prods": {
            "u_mtx": 7, 
            "cod_mtx": prod.SKU_ID || "VAR", 
            "ds": prod["Nombre del producto"], 
            "qty": cantidad,
            "price": precioUnitario,
            "neto": netoLinea,
            "iva_id": idAlicuota, 
            "imp_iva": ivaLinea,
            "item_total": totalLinea
        }
    });
}

// 5. APLICACIÓN DEL DESCUENTO
if (montoDescuento > 0) {
    const descuentoNeto = (parseFloat(montoDescuento) * -1);
    let tasaIvaDesc = [1, 3, 6, 8].includes(codigoAfip) ? 0.21 : 0;
    let idAlicuotaDesc = [1, 3, 6, 8].includes(codigoAfip) ? 5 : 3;

    const descuentoIva = parseFloat((descuentoNeto * tasaIvaDesc).toFixed(2));
    const descuentoTotal = parseFloat((descuentoNeto + descuentoIva).toFixed(2));

    totalNeto += descuentoNeto;
    totalIva += descuentoIva;
    totalComprobante += descuentoTotal;

    detalleItemsParaAfip.push({
        "Prods": {
            "u_mtx": 7,
            "cod_mtx": "DESC",
            "ds": "Descuento Aplicado",
            "qty": 1,
            "price": descuentoNeto,
            "neto": descuentoNeto,
            "iva_id": idAlicuotaDesc,
            "imp_iva": descuentoIva,
            "item_total": descuentoTotal
        }
    });
}

// 6. REDONDEO FINAL
totalNeto = parseFloat(totalNeto.toFixed(2));
totalIva = parseFloat(totalIva.toFixed(2));
totalComprobante = parseFloat(totalComprobante.toFixed(2));

return {
    json: {
        CbteTipo: codigoAfip,
        cliente_doc: cabecera.Cuit_Receptor, 
        ItemsDetalle: detalleItemsParaAfip,
        ImporteNeto: totalNeto,
        ImporteIva: totalIva,
        ImporteTotal: totalComprobante,
        Fecha: new Date().toISOString().slice(0,10).replace(/-/g, ''),
        // Debug para que veas qué detectó el código
        debug: {
            tipoDetectado: tipoOriginal,
            codigoAfipAsignado: codigoAfip
        }
    }
};

// 1. OBTENER TODO EL TEXTO (Convierte el JSON entero a texto para no fallar)
const entrada = items[0].json;
const texto = typeof entrada === 'string' ? entrada : JSON.stringify(entrada);

// 2. BUSCAR TODOS LOS GRUPOS DE NÚMEROS POSIBLES
// Busca secuencias de números que pueden tener puntos o guiones
const posibles = texto.match(/[0-9][0-9\.\-]{6,15}[0-9]/g);

let cuit = null;
let dni = null;

if (posibles) {
    for (let candidato of posibles) {
        // Limpiamos: dejamos solo números puros
        let numero = candidato.replace(/[^0-9]/g, "");

        // REGLA SIMPLE: POR LONGITUD
        if (numero.length === 11) {
            // Si empieza con 20, 23, 27, 30, 33 o 34 es un CUIT (filtro anti-celulares)
            const prefijo = parseInt(numero.substring(0, 2));
            if ([20, 23, 24, 27, 30, 33, 34].includes(prefijo)) {
                cuit = numero;
            }
        } 
        else if (numero.length === 7 || numero.length === 8) {
            // Si es mayor a 2 millones, es un DNI (filtro anti-precios)
            if (parseInt(numero) > 2000000) {
                dni = numero;
            }
        }
    }
}

// 3. PREPARAR DATOS PARA AFIP (Prioridad: CUIT mata DNI)
let afipNumero = 0;
let afipTipoDoc = 99; // Por defecto: Consumidor Final
let afipTipoCbte = 6; // Por defecto: Factura B

if (cuit) {
    afipNumero = parseInt(cuit);
    afipTipoDoc = 80; // CUIT
    afipTipoCbte = 1; // Factura A
} else if (dni) {
    afipNumero = parseInt(dni);
    afipTipoDoc = 96; // DNI
    afipTipoCbte = 6; // Factura B
}

// 4. RESULTADO
return {
    json: {
        // LO QUE PEDISTE: Muestra los dos por separado
        cuit_detectado: cuit|| "NO_ENCONTRADO",
        dni_detectado: dni || "NO_ENCONTRADO",

        // DATOS TÉCNICOS: Lo que usará el nodo de AFIP
        afip_doc_nro: afipNumero,
        afip_doc_tipo: afipTipoDoc,
        afip_cbte_tipo: afipTipoCbte
    }
}

// OBTENEMOS EL CUERPO DEL WEBHOOK (desde Webhook1, no desde items)
const body = $('Webhook').first().json.body;

// --- LÓGICA DE FECHA PARA AFIP ---
const rawDate = body.date || body.invoiceDate || null;
let fechaAfip = "";
if (rawDate) {
    fechaAfip = rawDate.toString().substring(0, 10).replace(/-/g, '');
} else {
    fechaAfip = new Date().toISOString().substring(0, 10).replace(/-/g, '');
}

// OBTENEMOS LAS LISTAS
const listaProductos = body.items || [];
const cliente = body.client || {};
const mensaje = body.message || {};
const emisor = body.emisor || {};

let resultado = [];

// RECORREMOS CADA PRODUCTO QUE LLEGÓ EN EL WEBHOOK
for (const prod of listaProductos) {
    resultado.push({
        json: {
            "Mensaje": mensaje.text,
            "Cuit_Receptor": cliente.cuit,
            "email_Receptor": cliente.email,
            "TipoDeFactura": body.type,
            "creditNote": body.creditNote || body.creditnote || false,
            "FechaComprobante": fechaAfip,
            "NroFacturaOriginal": body.originalInvoiceNumber || null,
            "Cantidad": prod.quantity,
            "Nombre del producto": prod.productName,
            "Producto ID": prod.productId,
            "SKU_ID": prod.sku,
            "PrecioUnitario": prod.unitPrice,
            "IVA": prod.vatRate,
            "Numero de despacho": prod.dispachNumber || "",
            "origen": prod.origin || "",
            "emisor": emisor
        }
    });
}

return resultado;

const PUNTO_VENTA = $('Webhook').first().json.body.emisor.puntoVenta || 1;

// Obtenemos los datos del nodo anterior (Input directo)
const input = $input.first().json;

// --- 1. RESCATE DE DATOS DESDE WEBHOOK (FECHA, CAE y VAT) ---
let vatTotalWebhook = 0;
let caeOriginal = "";
// Por defecto usamos la fecha de hoy
let fechaParaAfip = new Date().toISOString().slice(0,10).replace(/-/g, ''); 

try {
    // Intentamos leer el body del Webhook
    const webhookData = $('Webhook').first().json;
    const body = webhookData.body || {}; 

    // A. Rescate de datos específicos de NC
    vatTotalWebhook = parseFloat(body.vatTotal || 0);
    caeOriginal = body.originalInvoiceCAE || "";

    // B. Rescate de la fecha
    let fechaWebhook = body.date || body.fecha || null;

    if (fechaWebhook) {
        // Formateamos a YYYYMMDD
        fechaParaAfip = fechaWebhook.toString().slice(0,10).replace(/-/g, '');
    }

} catch (e) {
    // Si falla el webhook, usamos valores del input si existen o defaults
    caeOriginal = input.cae_original || "";
}

// --- 1.B. RESCATE DE FECHA VENCIMIENTO ---
let fechaVtoParaAfip = fechaParaAfip; // Default: Vence el mismo día

try {
    const datosRecibo = $('Recibo Datos').first().json;
    let rawVto = datosRecibo.fechaVencimiento || datosRecibo.vencimiento || null;

    if (rawVto) {
        let vtoLimpio = rawVto.toString().slice(0,10).replace(/-/g, '');
        // VALIDACIÓN AFIP: El vencimiento debe ser >= a la fecha de la NC
        if (parseInt(vtoLimpio) >= parseInt(fechaParaAfip)) {
            fechaVtoParaAfip = vtoLimpio;
        } else {
            fechaVtoParaAfip = fechaParaAfip;
        }
    }
} catch (e) {
    fechaVtoParaAfip = fechaParaAfip;
}

// --- 2. RESCATE DE DATOS ORIGINALES (NRO Y PTO VENTA) ---
let nroFacturaOriginal = 0;
let ptoVtaOriginal = 5; // Default usual (el 5 es tu automático)

try {
    // Intentamos buscar datos en nodos anteriores
    const dataNodoRef = $('Code in JavaScript16').first().json; // O el nodo que tenga la data original
    nroFacturaOriginal = parseInt(dataNodoRef.NroFacturaOriginal || dataNodoRef.nroFacturaOriginal || 0);

    // Si tenemos el punto de venta original guardado, lo usamos. Si no, asumimos 5.
    if (dataNodoRef.PtoVtaOriginal) {
        ptoVtaOriginal = parseInt(dataNodoRef.PtoVtaOriginal);
    }
} catch (e) {
    nroFacturaOriginal = parseInt(input.NroFacturaOriginal || input.nro_factura_original || 0);
}

// --- 3. CONFIGURACIÓN ---
const TIPO_COMPROBANTE = 3; // Nota de Crédito A

// --- 4. IDENTIFICACIÓN DEL CLIENTE ---
let cuitCliente = parseFloat(input.cliente_doc || input.cuit || 0);
const docTipo = 80; 

// --- 5. CÁLCULO DE ÍTEMS ---
let sumaNeto = 0;
let ivaAccumulator = {}; 

const items = input.ItemsDetalle || [];
const itemsParaAfip = [];

items.forEach(itemWrapper => {
    const prod = itemWrapper.Prods || itemWrapper; 

    if (prod) {
        const netoItem = parseFloat(prod.neto || 0);
        const ivaId = parseInt(prod.iva_id || 5); // 5 = 21%
        const ivaItem = parseFloat(prod.imp_iva || 0);

        sumaNeto += netoItem;

        if (!ivaAccumulator[ivaId]) {
            ivaAccumulator[ivaId] = { Id: ivaId, BaseImp: 0, Importe: 0 };
        }
        ivaAccumulator[ivaId].BaseImp += netoItem;
        ivaAccumulator[ivaId].Importe += ivaItem;

        itemsParaAfip.push({ "Prods": prod });
    }
});

// --- 6. REDONDEO Y ASIGNACIÓN DE IVA ---
const totalNetoFinal = parseFloat(sumaNeto.toFixed(2));
const totalIvaFinal = vatTotalWebhook > 0 ? parseFloat(vatTotalWebhook.toFixed(2)) : parseFloat(Object.values(ivaAccumulator).reduce((a, b) => a + b.Importe, 0).toFixed(2));
const totalFinal = parseFloat((totalNetoFinal + totalIvaFinal).toFixed(2));

// --- 7. ARRAY 'IVA' FINAL ---
let arrayIvaFinal = [];
for (const key in ivaAccumulator) {
    if (Math.abs(ivaAccumulator[key].BaseImp) > 0.009) {
        let importeIvaDinamico = (Object.keys(ivaAccumulator).length === 1) ? totalIvaFinal : parseFloat(ivaAccumulator[key].Importe.toFixed(2));

        arrayIvaFinal.push({
            "Id": ivaAccumulator[key].Id,
            "BaseImp": parseFloat(ivaAccumulator[key].BaseImp.toFixed(2)),
            "Importe": importeIvaDinamico
        });
    }
}

// --- 8. ARMADO DEL OBJETO FINAL ---
const detalle = {
    "Concepto": 3,  // <--- CAMBIADO A 3 (PRODUCTOS Y SERVICIOS) para evitar problemas de fechas
    "DocTipo": docTipo,
    "DocNro": cuitCliente,
    "CbteFch": fechaParaAfip,

    // --- CAMPOS OBLIGATORIOS PARA CONCEPTO 2 o 3 (AGREGADOS) ---
    "FchServDesde": fechaParaAfip,
    "FchServHasta": fechaParaAfip,
    "FchVtoPago": fechaVtoParaAfip, 
    // -----------------------------------------------------------

    "ImpTotal": totalFinal,
    "ImpTotConc": 0,
    "ImpNeto": totalNetoFinal,
    "ImpOpEx": 0,
    "ImpTrib": 0,
    "ImpIVA": totalIvaFinal,

    "MonId": "PES",
    "MonCotiz": 1,

    "Iva": arrayIvaFinal,

    "CbtesAsoc": [
        {
            "Tipo": 1, // Factura A asociada
            "PtoVta": ptoVtaOriginal, // Usamos el detectado (o 5 por defecto), NO el 4 de la NC
            "Nro": nroFacturaOriginal,
            "Cuit": cuitCliente,
            "Cae": caeOriginal 
        }
    ]
};

return {
    json: {
        PtoVta: PUNTO_VENTA,
        CbteTipo: TIPO_COMPROBANTE,
        cuit: cuitCliente,
        detalleParaAfip: detalle,
        ItemsDetalle: itemsParaAfip,
        nro_factura_original: nroFacturaOriginal,
        cae_original: caeOriginal,
        debug_iva_webhook: vatTotalWebhook,
        debug_fecha_usada: fechaParaAfip,
        debug_concepto_usado: 3
    }
};

const PUNTO_VENTA = $('Webhook').first().json.body.emisor.puntoVenta || 1;

// =========================
// NOTA DE CRÉDITO C (CbteTipo 13)
// =========================

// Obtenemos los datos del nodo anterior
const input = $input.first().json;

// --- 1. RESCATE DE DATOS (FECHAS Y FACTURA ORIGINAL) ---

// A. Lógica de Fecha Comprobante (Desde Webhook)
let fechaParaAfip = new Date().toISOString().slice(0, 10).replace(/-/g, '');

try {
  const webhookData = $('Webhook').first().json.body;
  let fechaWebhook = webhookData.date || webhookData.fecha || null;

  if (fechaWebhook) {
    // Formateamos a YYYYMMDD
    fechaParaAfip = fechaWebhook.toString().slice(0, 10).replace(/-/g, '');
  }
} catch (e) {
  // Si falla el webhook, queda la fecha de hoy definida arriba
}

// B. Lógica de Fecha de Vencimiento (Nueva lógica igual a Factura A)
let fechaVtoParaAfip = fechaParaAfip; // Default: Vence el mismo día

try {
    // Buscamos los datos en "Recibo Datos1"
    const datosRecibo = $('Recibo Datos').first().json;

    // Buscamos el campo "fechaVencimiento" (o "vencimiento")
    let rawVto = datosRecibo.fechaVencimiento || datosRecibo.vencimiento || null;

    if (rawVto) {
        let vtoLimpio = rawVto.toString().slice(0,10).replace(/-/g, '');
        // VALIDACIÓN AFIP: El vencimiento debe ser >= a la fecha de la factura
        if (parseInt(vtoLimpio) >= parseInt(fechaParaAfip)) {
            fechaVtoParaAfip = vtoLimpio;
        } else {
            fechaVtoParaAfip = fechaParaAfip;
        }
    }
} catch (e) {
    fechaVtoParaAfip = fechaParaAfip;
}

// C. Rescate del Nro Factura Original
let nroFacturaOriginal = 0;
try {
  const dataNodoRef = $('Code in JavaScript16').first().json;
  nroFacturaOriginal = parseInt(dataNodoRef.NroFacturaOriginal || dataNodoRef.nroFacturaOriginal || 0, 10);
} catch (e) {
  nroFacturaOriginal = parseInt(input.NroFacturaOriginal || input.nro_factura_original || 0, 10);
}

// --- 2. CONFIGURACIÓN ---
const TIPO_COMPROBANTE = 13; // 13 = NOTA DE CRÉDITO C

// --- 3. IDENTIFICACIÓN DEL CLIENTE ---
let rawDoc = input.cliente_doc || input.cuit || 0;
let strDoc = String(rawDoc).replace(/\D/g, '');

let docTipo = 99;      // 99 = Consumidor Final
let docNro = 0;        // en CF debe ser 0

if (strDoc.length === 11) {
  docTipo = 80;                 // 80 = CUIT
  docNro = Number(strDoc);
} else if (strDoc.length >= 7 && strDoc.length <= 8) {
  docTipo = 96;                 // 96 = DNI
  docNro = Number(strDoc);
} else {
  docTipo = 99;
  docNro = 0;
}

// --- 4. CÁLCULO DE ÍTEMS (TIPO C: TOTAL = NETO) ---
let sumaTotal = 0;
const items = input.ItemsDetalle || [];
const itemsParaAfip = [];

items.forEach((itemWrapper) => {
  const prod = itemWrapper.Prods || itemWrapper;

  if (prod) {
    const totalItem = parseFloat(prod.item_total || 0);
    sumaTotal += totalItem;
    itemsParaAfip.push({ Prods: prod });
  }
});

// --- 5. REDONDEO ---
const totalFinal = parseFloat(sumaTotal.toFixed(2));

// --- 6. COMPROBANTE ASOCIADO (FACTURA C = Tipo 11) ---
const cbteAsoc = {
  Tipo: 11,              // 11 = FACTURA C
  PtoVta: PUNTO_VENTA,
  Nro: nroFacturaOriginal,
};

// Solo agregamos Cuit si realmente es CUIT (evita undefined/null en payload)
if (docTipo === 80 && docNro > 0) {
  cbteAsoc.Cuit = docNro;
}

// --- 7. ARMADO DEL OBJETO FINAL ---
const detalle = {
  Concepto: 2, // <--- CAMBIO: Seteado en 2 (Servicios) para margen de 10 días
  DocTipo: docTipo,
  DocNro: docNro,
  CbteFch: fechaParaAfip,

  FchVtoPago: fechaVtoParaAfip, // <--- AGREGADO: Nueva fecha vencimiento

  // TIPO C:
  // Neto = Total, IVA = 0, no se discrimina IVA
  ImpTotal: totalFinal,
  ImpTotConc: 0,
  ImpNeto: totalFinal,
  ImpOpEx: 0,
  ImpTrib: 0,
  ImpIVA: 0,

  MonId: "PES",
  MonCotiz: 1,

  // IMPORTANTE: En Factura C esto va vacío.
  Iva: [],

  CbtesAsoc: [cbteAsoc],
};

return {
  json: {
    PtoVta: PUNTO_VENTA,
    CbteTipo: TIPO_COMPROBANTE,
    cuit: docNro, 

    detalleParaAfip: detalle,
    ItemsDetalle: itemsParaAfip,

    // Debug
    nro_factura_original: nroFacturaOriginal,
    tipo_doc: docTipo,
    debug_fecha_usada: fechaParaAfip,
    debug_vto_usado: fechaVtoParaAfip
  }
};

const PUNTO_VENTA = $('Webhook').first().json.body.emisor.puntoVenta || 1;

// Obtenemos los datos del nodo anterior
const input = $input.first().json;

// --- 1. RESCATE DE DATOS (FECHA Y NRO ORIGINAL) ---

// A. Lógica de Fecha (Desde Webhook)
let fechaParaAfip = new Date().toISOString().slice(0,10).replace(/-/g, ''); 

try {
    const webhookData = $('Webhook').first().json.body; 
    let fechaWebhook = webhookData.date || webhookData.fecha || null; 

    if (fechaWebhook) {
        // Formateamos a YYYYMMDD
        fechaParaAfip = fechaWebhook.toString().slice(0,10).replace(/-/g, '');
    }
} catch (e) {
    // Si falla la lectura del webhook, queda la fecha de hoy definida arriba
}

// B. Rescate del Nro Factura Original
let nroFacturaOriginal = 0;
try {
    const dataNodoRef = $('Code in JavaScript16').first().json;
    nroFacturaOriginal = parseInt(dataNodoRef.NroFacturaOriginal || dataNodoRef.nroFacturaOriginal || 0);
} catch (e) {
    nroFacturaOriginal = parseInt(input.NroFacturaOriginal || input.nro_factura_original || 0);
}

// --- 2. CONFIGURACIÓN ---
// const FECHA_HOY ... (Calculada arriba como 'fechaParaAfip')
const TIPO_COMPROBANTE = 8; // 8 es NOTA DE CRÉDITO B

// --- 3. IDENTIFICACIÓN DEL CLIENTE (LÓGICA FACTURA B) ---
// Detectamos CUIT, DNI o Consumidor Final según el largo del documento
let rawDoc = input.cliente_doc || input.cuit || 0;
let strDoc = String(rawDoc).replace(/\D/g, ''); 
let cuitCliente = parseFloat(strDoc);
let docTipo = 99; // Default: Consumidor Final

if (strDoc.length === 11) {
    docTipo = 80; // CUIT
} else if (strDoc.length >= 7 && strDoc.length <= 8) {
    docTipo = 96; // DNI
} else {
    // Si no es válido, Consumidor Final anónimo
    cuitCliente = 0;
    docTipo = 99; 
}

// --- 4. CÁLCULO DE ÍTEMS Y ARRAY DE IVA ---
// Mantenemos la lógica de suma precisa. Aunque en B no se muestra el IVA,
// AFIP pide el desglose interno.

let sumaNeto = 0;
let sumaIva = 0;
let sumaTotal = 0;
let ivaAccumulator = {}; 

const items = input.ItemsDetalle || [];
const itemsParaAfip = [];

items.forEach(itemWrapper => {
    const prod = itemWrapper.Prods || itemWrapper; 

    if (prod) {
        const netoItem = parseFloat(prod.neto || 0);
        const ivaId = parseInt(prod.iva_id || 5); // 5 = 21%
        const ivaItem = parseFloat(prod.imp_iva || 0);
        const totalItem = parseFloat(prod.item_total || 0);

        sumaNeto += netoItem;
        sumaIva += ivaItem;
        sumaTotal += totalItem;

        // Acumulamos alícuotas (Requisito técnico de AFIP para NC B también)
        if (!ivaAccumulator[ivaId]) {
            ivaAccumulator[ivaId] = { Id: ivaId, BaseImp: 0, Importe: 0 };
        }
        ivaAccumulator[ivaId].BaseImp += netoItem;
        ivaAccumulator[ivaId].Importe += ivaItem;

        itemsParaAfip.push({ "Prods": prod });
    }
});

// --- 5. REDONDEO ---
const totalNetoFinal = parseFloat(sumaNeto.toFixed(2));
const totalIvaFinal = parseFloat(sumaIva.toFixed(2));
const totalFinal = parseFloat(sumaTotal.toFixed(2));

// --- 6. ARRAY 'IVA' FINAL ---
let arrayIvaFinal = [];
for (const key in ivaAccumulator) {
    if (Math.abs(ivaAccumulator[key].BaseImp) > 0.009) {
        arrayIvaFinal.push({
            "Id": ivaAccumulator[key].Id,
            "BaseImp": parseFloat(ivaAccumulator[key].BaseImp.toFixed(2)),
            "Importe": parseFloat(ivaAccumulator[key].Importe.toFixed(2))
        });
    }
}

// --- 7. ARMADO DEL OBJETO FINAL ---
const detalle = {
    "Concepto": 1, 
    "DocTipo": docTipo,    // Variable (80, 96, 99)
    "DocNro": cuitCliente, // Variable
    "CbteFch": fechaParaAfip, // <--- CAMBIO: Usamos la fecha del Webhook

    "ImpTotal": totalFinal,
    "ImpTotConc": 0,
    "ImpNeto": totalNetoFinal,
    "ImpOpEx": 0,
    "ImpTrib": 0,
    "ImpIVA": totalIvaFinal,

    "MonId": "PES",
    "MonCotiz": 1,

    "Iva": arrayIvaFinal, 

    // --- DATOS DE LA NOTA DE CRÉDITO ---
    "CbtesAsoc": [
        {
            "Tipo": 6, // 6 = FACTURA B (Anulamos una B)
            "PtoVta": PUNTO_VENTA,
            "Nro": nroFacturaOriginal,
            "Cuit": cuitCliente > 0 ? cuitCliente : undefined 
        }
    ]
};

return {
    json: {
        PtoVta: PUNTO_VENTA,
        CbteTipo: TIPO_COMPROBANTE,
        cuit: cuitCliente,

        detalleParaAfip: detalle,
        ItemsDetalle: itemsParaAfip,

        // Debug
        nro_factura_original: nroFacturaOriginal,
        tipo_doc_detectado: docTipo,
        debug_fecha_usada: fechaParaAfip
    }
};

// Obtenemos los datos del nodo anterior
const input = $input.first().json;

// --- CONFIGURACIÓN FIJA ---
const FECHA_HOY = new Date().toISOString().slice(0,10).replace(/-/g, '');

// --- 1. DETECCIÓN DE FUENTE ---
// Verificamos si los nodos anteriores ya hicieron el trabajo duro.
// Los nodos nuevos (Factura A, B, C, Notas) envían 'detalleParaAfip'.
const detallePrearmado = input.detalleParaAfip;

// --- 2. ARMADO DEL OBJETO FINAL ---
let detalleFinal = {};

if (detallePrearmado) {
    // CASO A: Vienen datos listos de los nodos nuevos. USAMOS ESO.
    // Esto respeta los arrays de IVA complejos y los CbtesAsoc que ya calculamos.
    detalleFinal = detallePrearmado;
} else {
    // CASO B: Fallback (Por si entra algo viejo o simple).
    // Aquí sí aplicamos la lógica genérica que tenías antes.

    detalleFinal = {
        "Concepto": input.Concepto || 1,
        "DocTipo": input.DocTipo || 80,
        "DocNro": input.DocNro || input.cliente?.cuit || input.cuit,
        "CbteFch": input.CbteFch || FECHA_HOY,
        "ImpTotal": parseFloat(Number(input.ImpTotal).toFixed(2)),
        "ImpTotConc": 0,
        "ImpNeto": parseFloat(Number(input.ImpNeto).toFixed(2)),
        "ImpOpEx": 0,
        "ImpTrib": 0,
        "ImpIVA": parseFloat(Number(input.ImpIVA || 0).toFixed(2)),
        "MonId": "PES",
        "MonCotiz": 1
    };

    // Lógica básica de IVA (Solo 21%) para casos simples
    const tiposConIva = [1, 6, 3, 8]; 
    if (tiposConIva.includes(parseInt(input.CbteTipo)) && detalleFinal.ImpIVA > 0) {
        detalleFinal.Iva = [
            {
                "Id": 5, // 21%
                "BaseImp": detalleFinal.ImpNeto,
                "Importe": detalleFinal.ImpIVA
            }
        ];
    }

    // Rescate básico de comprobantes asociados
    if (input.CbtesAsoc) {
        detalleFinal.CbtesAsoc = input.CbtesAsoc;
    }
}

// --- 3. RETORNO FINAL ---
return {
    json: {
        // Datos de Ruteo (Siempre necesarios en la raíz)
        PtoVta: input.PtoVta || PUNTO_VENTA,
        CbteTipo: input.CbteTipo,

        // EL PAQUETE SAGRADO PARA AFIP
        detalleParaAfip: detalleFinal,

        // Datos Visuales (Pasan de largo para PDF/HTML)
        cliente: input.cliente || {},
        items: input.items || input.ItemsDetalle || [], // Compatibilidad con ambos nombres

        // Metadatos
        meta: {
            mensaje: input.meta?.mensaje,
            esNotaCredito: input.meta?.esNotaCredito || false,
            descuento_aplicado: input.descuento_aplicado // Info útil para debug
        }
    }
};

const emisorWebhook = $('Webhook').first().json.body.emisor || {};
const emisor = {
  razonSocial: emisorWebhook.razonSocial || "SIN CONFIGURAR",
  domicilio: emisorWebhook.domicilio || "-",
  condicionIva: emisorWebhook.condicionIva || "-",
  iibb: emisorWebhook.iibb || "-",
  inicioAct: emisorWebhook.inicioActividades || "-"
};
const CUIT_EMISOR = Number($('Config Credenciales1').first().json.authBody.tax_id);

// =========================
// NC - DATA MODEL PARA HTML (robusto) + QR SIEMPRE
// Nodos usados:
// - webhook1 (o Webhook1)
// - get_persona1
// - generate_qr_text   (opcional: si no está, igual genera QR)
// =========================

// 1) TRAER WEBHOOK
let body = {};
try {
  body = $('webhook1').first().json.body;
} catch (e) {
  try { body = $('Webhook').first().json.body; }
  catch (e2) { throw new Error("❌ ERROR: No encuentro el nodo 'webhook1'."); }
}

// 2) TRAER GET PERSONA
let personaWrap = {};
try {
  personaWrap = $('get_persona').first().json;
} catch (e) {
  personaWrap = {};
}

// 3) TRAER QR NODE (PUEDE NO HABERSE EJECUTADO)
let qrNode = null;
try {
  qrNode = $('generate_qr_text1').first().json; // <-- SIN 4
} catch (e) {
  qrNode = null;
}

// 4) EMISOR
const CUIT_EMISOR = Number($('Config Credenciales1').first().json.authBody.tax_id);
const emisorWH = $('Webhook').first().json.body.emisor || {};
const emisor = {
  razonSocial: emisorWH.razonSocial || "SIN CONFIGURAR",
  domicilio: emisorWH.domicilio || "-",
  condicionIva: emisorWH.condicionIva || "-",
  iibb: emisorWH.iibb || String(CUIT_EMISOR),
  inicioAct: emisorWH.inicioActividades || "-"
};

// 5) HELPERS
const money = new Intl.NumberFormat('es-AR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
const pad = (num, size) => ('000000000' + (num ?? 0)).slice(-size);

const formatFechaQR = (f) => {
  f = String(f || "");
  // YYYYMMDD
  if (f.length === 8 && /^\d{8}$/.test(f)) return `${f.slice(0,4)}-${f.slice(4,6)}-${f.slice(6,8)}`;
  // ISO o Date
  try { return new Date(f).toISOString().slice(0, 10); } catch { return ""; }
};

// 6) DIRECCIÓN DEL CLIENTE DESDE get_persona1 (FISCAL > LEGAL/REAL > primero)
const domicilios = personaWrap?.personaReturn?.persona?.domicilio || [];
const domFiscal = domicilios.find(d => d.tipoDomicilio === "FISCAL");
const domLegal = domicilios.find(d => d.tipoDomicilio === "LEGAL/REAL");
const domElegido = domFiscal || domLegal || domicilios[0] || null;

const direccionCliente = (domElegido?.direccion) || (body?.client?.address) || "-";

// 7) TABLA PRODUCTOS
let itemsHtml = "";
let tasaIva = "21";

if (body.items && body.items.length) {
  tasaIva = (body.items[0].vatRate != null) ? money.format(body.items[0].vatRate) : "21";

  itemsHtml = body.items.map(it => `
    <tr>
      <td>${it.sku || '-'}</td>
      <td>${it.productName || 'Concepto'}</td>
      <td class="text-center">${it.quantity ?? 0}</td>
      <td class="text-center">unidades</td>
      <td class="text-right">${money.format(Number(it.unitPrice || 0))}</td>
      <td class="text-right">${money.format(Number(it.subtotal || 0))}</td>
    </tr>
  `).join('');
}

// 8) LETRA / TIPO (si no hay qrNode, lo inferimos del texto body.type)
let tipoCmp = qrNode?.tipo_comprobante;

if (!tipoCmp) {
  const t = (body.type || "").toLowerCase();
  if (t.includes("crédito a")) tipoCmp = 3;
  else if (t.includes("crédito b")) tipoCmp = 8;
  else if (t.includes("crédito c")) tipoCmp = 13;
  else tipoCmp = 13;
}

tipoCmp = Number(tipoCmp);
const letrasNC = { 3: 'A', 8: 'B', 13: 'C', 53: 'M' };
const letra = letrasNC[tipoCmp] || 'C';
const codigoComprobante = pad(tipoCmp, 3);

// 9) ASOCIADO (factura original)
const asociadoTxt = `Factura original Nro: ${body.originalInvoiceId || body.invoiceId || '-'} · CAE: ${body.originalInvoiceCAE || '-'}`;

// 10) GENERAR QR SIEMPRE (LINK AFIP + IMG)
// Tomamos lo que venga de qrNode si está, si no usamos defaults
const ptoVtaQR = Number(qrNode?.punto_venta || 4);
const nroCmpQR = Number(qrNode?.numero_comprobante || 0);
const caeQR = String(qrNode?.cod_autorizacion || "").trim();
const vtoQR = String(qrNode?.vto_cae || "").trim();
const fechaCmp = qrNode?.fecha_emision || (body.date ? new Date(body.date).toISOString().slice(0, 10) : "");

// Data QR oficial AFIP
const qrData = {
  ver: 1,
  fecha: formatFechaQR(fechaCmp),
  cuit: CUIT_EMISOR,
  ptoVta: ptoVtaQR,
  tipoCmp: Number(tipoCmp),
  nroCmp: nroCmpQR,
  importe: Number(body.total || 0),
  moneda: "PES",
  ctz: 1,
  tipoDocRec: 80,
  nroDocRec: Number(body.client?.cuit || 0),
  tipoCodAut: "E",
  codAut: caeQR ? Number(caeQR) : 0
};

const urlQrAfip = `https://www.afip.gob.ar/fe/qr/?p=${Buffer.from(JSON.stringify(qrData)).toString('base64')}`;

// Imagen del QR (esto es lo que va en el <img src="...">)
const qrImageUrl = `https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=${encodeURIComponent(urlQrAfip)}`;

// QR para HTML
const qr = {
  img: qrImageUrl,
  cae: caeQR,
  vto: vtoQR
};

// 11) FACTURA (NC)
const factura = {
  titulo: "NOTA DE CRÉDITO",
  letra,
  codigo: codigoComprobante,
  ptoVta: pad(ptoVtaQR, 5),
  numero: pad(nroCmpQR, 8),
  fecha: formatFechaQR(fechaCmp),
  vencimiento: formatFechaQR(fechaCmp),
  asociado: asociadoTxt
};

// 12) SALIDA PARA HTML
return {
  emisor,

  cliente: {
    nombre: body.client?.name || "Consumidor Final",
    cuit: body.client?.cuit || "0",
    condicionIva: body.client?.taxCondition || "Consumidor Final",
    domicilio: direccionCliente
  },

  factura,

  totales: {
    subtotal: money.format(Number(body.subtotal || 0)),
    descuento: money.format(Number(body.discountAmount || 0)),
    neto: money.format(Number(body.netTaxable || 0)),
    iva: money.format(Number(body.vatTotal || 0)),
    tasa_iva: tasaIva,
    total: money.format(Number(body.total || 0)),
    moneda: "$"
  },

  qr,
  tabla_productos: itemsHtml,

  // opcional para tu HTML (si querés que sea clickeable)
  qr_link_afip: urlQrAfip
};

const emisorWebhook = $('Webhook').first().json.body.emisor || {};
const emisor = {
  razonSocial: emisorWebhook.razonSocial || "SIN CONFIGURAR",
  domicilio: emisorWebhook.domicilio || "-",
  condicionIva: emisorWebhook.condicionIva || "-",
  iibb: emisorWebhook.iibb || "-",
  inicioAct: emisorWebhook.inicioActividades || "-"
};
const CUIT_EMISOR = Number($('Config Credenciales1').first().json.authBody.tax_id);

// =========================
// Code in JavaScript3 (Data para HTML - Nota de Crédito)
// =========================

// 1) TRAER UNIFICADOR (Fuente de verdad de importes y fechas)
let uni = {};
try {
  uni = $('Code Unificador1').first().json;
} catch (e) {
  console.log("⚠️ No se encontró 'Code Unificador'");
}

// 2) TRAER WEBHOOK (Para datos de cliente y productos)
let wb = {};
try {
  wb = $('Webhook').first().json.body || {};
} catch (e) {
  try { wb = $('webhook1').first().json.body || {}; } catch (e2) {}
}

// 3) TRAER CREATE_VOUCHER1 (Fuente de verdad del CAE y Numero real)
let cabecera = {};
let detAfip = {};
try {
  const cv = $('create_voucher').first().json; 

  const r = cv.FECAESolicitarResult || {};
  cabecera = r.FeCabResp || {};

  if (r.FeDetResp && r.FeDetResp.FECAEDetResponse && r.FeDetResp.FECAEDetResponse[0]) {
      detAfip = r.FeDetResp.FECAEDetResponse[0];
  }
} catch (e) {
  console.log("⚠️ No se pudo leer 'create_voucher1'");
}

// 4) TRAER QR (Opcional)
let qrNode = null;
try {
  qrNode = $('generate_qr_text1').first().json;
} catch (e) { qrNode = null; }

// 5) HELPERS DE FORMATO
const pad = (num, size) => ('000000000' + (num ?? 0)).slice(-size);
const formatFecha = (f) => {
  const s = String(f || "");
  if (s.length === 8 && /^\d{8}$/.test(s)) return `${s.slice(6,8)}/${s.slice(4,6)}/${s.slice(0,4)}`;
  return ""; 
};
const moneyStr = (n) => Number(n || 0).toLocaleString('es-AR', {minimumFractionDigits: 2, maximumFractionDigits: 2});

// 6) DATOS DEL UNIFICADOR
const detalle = uni.detalleParaAfip || {};
const impNeto  = parseFloat(detalle.ImpNeto || 0);
const impIVA   = parseFloat(detalle.ImpIVA || 0);
const impTotal = parseFloat(detalle.ImpTotal || 0);

const fechaEmision = formatFecha(detalle.CbteFch);
const fDesde = formatFecha(detalle.FchServDesde);
const fHasta = formatFecha(detalle.FchServHasta);
const fVto   = formatFecha(detalle.FchVtoPago || detalle.CbteFch);
const concepto = detalle.Concepto || 1;

// 7) DATOS DE AFIP (CAE y NUMERO ACTUAL)
const ptoVtaNum = Number(cabecera.PtoVta || uni.PtoVta || 0);
const nroNum    = Number(detAfip.CbteDesde || detAfip.CbteHasta || 0);
const caeFinal  = String(detAfip.CAE || "");
const vtoCaeFinal = formatFecha(detAfip.CAEFchVto || "");

const tipoCmp = Number(uni.CbteTipo || cabecera.CbteTipo || 0);
const letrasNC = { 1:'A', 6:'B', 11:'C', 3:'A', 8:'B', 13:'C' };
const letra = letrasNC[tipoCmp] || 'C'; 
const codigo = String(tipoCmp).padStart(3, '0');

// 8) TABLA PRODUCTOS --- AQUÍ ESTÁ EL CAMBIO DE FORMATO ---
let itemsHtml = uni.f_tabla_body || "";

if (!itemsHtml && wb.items) {
  itemsHtml = wb.items.map(item => {

    // Datos base
    const nombre = item.productName || "Concepto";
    const sku = item.sku || "";
    const desp = item.dispatchNumber; // Puede ser null/undefined
    const org = item.origin;          // Puede ser null/undefined

    // --- LÓGICA DE FORMATO EXACTO FOTO ---
    // Queremos: "Nombre (Desp: XXX Org: YYY)"
    let descripcionFinal = nombre;

    // Solo agregamos paréntesis si hay info de despacho u origen
    if (desp || org) {
        let extras = [];
        if (desp) extras.push(`Desp: ${desp}`);
        if (org)  extras.push(`Org: ${org}`);

        // Unimos con espacio y envolvemos en paréntesis
        descripcionFinal += ` (${extras.join(' ')})`;
    }

    return `
      <tr>
        <td>${sku}</td>
        <td>${descripcionFinal}</td> <td class="text-center">${item.quantity ?? 1}</td>
        <td class="text-center">u.</td>
        <td class="text-right">${moneyStr(item.unitPrice || 0)}</td>
        <td class="text-right">${moneyStr(item.subtotal || 0)}</td>
      </tr>
    `;
  }).join('');
}

// 9) ASOCIADO (Caja Amarilla)
// Buscamos "originalInvoiceCae" (minúscula) y "originalInvoiceCAE" (mayúscula)
const origNum = wb.originalInvoiceNumber || wb.originalInvoiceId || "-";
const origCae = wb.originalInvoiceCAE || wb.originalInvoiceCae || "-";

const f_asociado = (origNum !== "-" || origCae !== "-")
    ? `Comprobante Asociado: ${origNum} (CAE: ${origCae})`
    : "";

// 10) QR
let qrImg = "https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=AFIP";
if (qrNode && qrNode.qr_url) qrImg = qrNode.qr_url;

// 11) EMISOR
const emisorWH = $('Webhook').first().json.body.emisor || {};
const emisor = {
  razonSocial: emisorWH.razonSocial || "SIN CONFIGURAR",
  domicilio: emisorWH.domicilio || "-",
  condicionIva: emisorWH.condicionIva || "-",
  iibb: emisorWH.iibb || "-",
  inicioAct: emisorWH.inicioActividades || "-"
};

// RETORNO FINAL
return {
  emisor,
  cliente: {
    nombre: wb.client?.name || "Consumidor Final",
    cuit: wb.client?.cuit || "0",
    condicionIva: wb.client?.tax_condition || wb.client?.taxCondition || "Consumidor Final",
    domicilio: wb.client?.address || "-"
  },
  factura: {
    letra: letra,
    codigo: codigo,
    ptoVta: pad(ptoVtaNum, 5),
    numero: pad(nroNum, 8),
    fecha: fechaEmision,
    vencimiento: fVto,
    concepto: concepto,
    serv_desde: fDesde,
    serv_hasta: fHasta
  },
  totales: {
    subtotal: moneyStr(impNeto), 
    descuento: moneyStr(uni.descuento_aplicado || 0),
    neto: moneyStr(impNeto),
    iva: moneyStr(impIVA),
    tasa_iva: String(wb.items?.[0]?.vatRate ?? 21),
    total: moneyStr(impTotal),
    moneda: "$"
  },
  qr: {
    img: qrImg,
    cae: caeFinal,
    vto: vtoCaeFinal
  },
  f_titulo: "NOTA DE CRÉDITO",
  f_asociado: f_asociado, 
  tabla_productos: itemsHtml
};

