parameters.jsCode:
// 1. OBTENCIÓN DE DATOS
// Estrategia Segura: Usamos 'items[0].json' para los datos de AFIP
// (ya que este nodo recibe los datos directamente del If1 <- create_voucher4)
let voucherNode;
try {
    voucherNode = items[0].json;
    // Validación básica para asegurar que tenemos datos de AFIP
    if (!voucherNode.FECAESolicitarResult) {
        // Si no está en el input, intentamos buscarlo por nombre como respaldo
        voucherNode = $('create_voucher8').first().json;
    }
} catch (e) {
    throw new Error("❌ No encuentro los datos de AFIP. Asegúrate que la factura se creó correctamente (Resultado A).");
}

// Para el Code Unificador sí necesitamos buscar por nombre.
// ATENCIÓN: Si esto falla, verifica que el nodo se llame EXACTAMENTE "Code Unificador1" (sin espacios extra).
let unificadorNode;
try {
    unificadorNode = $('Code Unificador4').first().json;
} catch (e) {
    throw new Error("❌ No encuentro el nodo 'Code Unificador1'. Por favor revisa si tiene un espacio al final del nombre.");
}

// Asignación de variables cortas
const detResp = voucherNode.FECAESolicitarResult.FeDetResp.FECAEDetResponse[0];
const cabResp = voucherNode.FECAESolicitarResult.FeCabResp;
const detAfip = unificadorNode.detalleParaAfip;

// 2. FORMATEO
// Fecha: YYYYMMDD -> YYYY-MM-DD
const rawDate = String(detResp.CbteFch);
const formattedDate = `${rawDate.substring(0, 4)}-${rawDate.substring(4, 6)}-${rawDate.substring(6, 8)}`;

// Número de Comprobante
// Usamos el que devuelve AFIP en esta misma transacción (CbteDesde). Es lo más seguro.
const nroComprobante = detResp.CbteDesde;

// 3. ARMADO DEL JSON (Formato AFIP Oficial)
const qrDataObj = {
    "ver": 1,
    "fecha": formattedDate,
    "cuit": parseInt(cabResp.Cuit),
    "ptoVta": parseInt(cabResp.PtoVta),
    "tipoCmp": parseInt(cabResp.CbteTipo),
    "nroCmp": parseInt(nroComprobante),
    "importe": parseFloat(detAfip.ImpTotal),
    "moneda": detAfip.MonId,
    "ctz": parseFloat(detAfip.MonCotiz),
    "tipoDocRec": parseInt(detAfip.DocTipo),
    "nroDocRec": parseInt(detAfip.DocNro),
    "tipoCodAut": "E",
    "codAut": parseInt(detResp.CAE || 0)
};

// 4. GENERACIÓN URL
const jsonString = JSON.stringify(qrDataObj);
const base64Data = Buffer.from(jsonString).toString('base64');
const qrUrl = `https://www.afip.gob.ar/fe/qr/?p=${base64Data}`;

// 5. RETORNO
return {
    json: {
        // Datos formateados listos para tu HTML
        fecha_emision: formattedDate,
        cuit_emisor: cabResp.Cuit,
        punto_venta: cabResp.PtoVta,
        tipo_comprobante: cabResp.CbteTipo,
