const sourceData = input.detalleParaAfip || input;

const neto = parseFloat(Number(sourceData.ImpNeto || 0).toFixed(2));
const iva = parseFloat(Number(sourceData.ImpIVA || 0).toFixed(2));
const tributos = parseFloat(Number(sourceData.ImpTrib || 0).toFixed(2));
const opEx = parseFloat(Number(sourceData.ImpOpEx || 0).toFixed(2));

// Si ya venía un Total calculado, lo usamos, si no, lo recalculamos
let totalCalculado = 0;
if (sourceData.ImpTotal) {
    totalCalculado = parseFloat(Number(sourceData.ImpTotal).toFixed(2));
} else {
    totalCalculado = parseFloat((neto + iva + tributos + opEx).toFixed(2));
}

// --- 7. ARMADO DEL OBJETO "DETALLE" ---

// Recuperamos el concepto REAL que viene del nodo anterior (o del input)
// Si no viene, asume 1 (Productos), pero si es 3 necesitamos saberlo.
const conceptoFinal = sourceData.Concepto || input.Concepto || 1;

const detalle = {
    "Concepto": conceptoFinal, 
    "DocTipo": sourceData.DocTipo || docTipoDefinitivo,
    "DocNro": sourceData.DocNro || docNumeroDefinitivo,

    // CAMBIO AQUÍ: Usamos la fecha procesada arriba
    "CbteFch": FECHA_USADA, 

    "ImpTotal": totalCalculado,
    "ImpTotConc": 0,
    "ImpNeto": neto,
    "ImpOpEx": opEx,
    "ImpTrib": tributos,
    "ImpIVA": iva,
    "MonId": "PES",
    "MonCotiz": 1
};

// --- CORRECCIÓN AGREGADA: INYECCIÓN DE FECHAS DE SERVICIO ---
// Si es Concepto 2 (Servicios) o 3 (Productos y Servicios), AFIP OBLIGA a tener estas fechas.
// Las igualamos a la fecha del comprobante para simplificar.
if (conceptoFinal === 2 || conceptoFinal === 3) {
    detalle.FchServDesde = FECHA_USADA;
    detalle.FchServHasta = FECHA_USADA;
    detalle.FchVtoPago   = FECHA_USADA;
}
// -----------------------------------------------------------

// --- 8. LÓGICA DE IVA ---
if (esFacturaC) {
    detalle.ImpIVA = 0;
    delete detalle.Iva; 
    if (detalle.ImpNeto === 0 && detalle.ImpTotal > 0) {
        detalle.ImpNeto = detalle.ImpTotal;
    }
} else {
    // FACTURA A y B
    // PRIORIDAD 1: Si viene el array listo desde Factura A
    if (sourceData.Iva && Array.isArray(sourceData.Iva) && sourceData.Iva.length > 0) {
         detalle.Iva = sourceData.Iva;
    }
    // PRIORIDAD 2: Si viene en el input raíz
    else if (input.Iva && Array.isArray(input.Iva) && input.Iva.length > 0) {
        detalle.Iva = input.Iva;
    } 
    // PRIORIDAD 3: Calcular uno genérico al 21%
    else if (detalle.ImpIVA > 0) {
        detalle.Iva = [{
            "Id": 5, // 21%
            "BaseImp": detalle.ImpNeto,
            "Importe": detalle.ImpIVA
        }];
    }
}

return {
    json: {
        // CAMBIO AQUÍ: Usamos la variable calculada (4 o 5)
        PtoVta: PUNTO_VENTA, 
        CbteTipo: tipoComprobante,

        // Output limpio
        cuit: docNumeroDefinitivo, 

        detalleParaAfip: detalle,

        cliente: input.cliente || {},
        items: input.items || [],

        // Debug info (útil para verificar)
        debug_fecha_usada: FECHA_USADA,
        debug_origen_pto_venta: PUNTO_VENTA,
        debug_concepto_final: conceptoFinal
    }
};

const emisorWebhook = $('Webhook').first().json.body.emisor || {};
const emisor = {
  razonSocial: emisorWebhook.razonSocial || "SIN CONFIGURAR",
  domicilio: emisorWebhook.domicilio || "-",
  condicionIva: emisorWebhook.condicionIva || "-",
  iibb: emisorWebhook.iibb || "-",
  inicioAct: emisorWebhook.inicioActividades || "-"
};
const CUIT_EMISOR = Number($('Config Credenciales1').first().json.authBody.tax_id);

let qrNode = {};
let webhookBody = {};
let unificadorNode = {}; 
let detAfip = {};

try {
    qrNode = $('generate_qr_text6').first().json; 
} catch (e) {
    qrNode = {};
}

try {
    try {
        webhookBody = $('webhook1').first().json.body;
    } catch (innerE) {
        webhookBody = $('Webhook').first().json.body;
    }
} catch (e) {
    throw new Error("ERROR: No encuentro el nodo 'webhook1'.");
}

try {
    unificadorNode = $('Code Unificador4').first().json;
} catch (e) {
    console.log("No se pudo leer Code Unificador4");
}

try {
    const cv = $('create_voucher9').first().json;
    const r = cv.FECAESolicitarResult || {};
    if (r.FeDetResp && r.FeDetResp.FECAEDetResponse && r.FeDetResp.FECAEDetResponse[0]) {
        detAfip = r.FeDetResp.FECAEDetResponse[0];
    }
} catch (e) {
    console.log("No se pudo leer create_voucher9. Usando fallback.");
}

const money = new Intl.NumberFormat('es-AR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
const pad = (num, size) => ('000000000' + (num ?? 0)).slice(-size);
const formatAfipDate = (dateStr) => {
    const s = String(dateStr || "");
    if (s.length !== 8) return ""; 
    return `${s.substring(6, 8)}/${s.substring(4, 6)}/${s.substring(0, 4)}`;
};

let itemsHtml = "";
let tasaIva = "21"; 
if (webhookBody.items && webhookBody.items.length > 0) {
    if (webhookBody.items[0].vatRate != null) {
        tasaIva = money.format(webhookBody.items[0].vatRate);
    }
    itemsHtml = webhookBody.items.map(item => {
        const nombre = item.productName || "Concepto";
        const sku = item.sku || "";
        const desp = item.dispatchNumber;
        const org = item.origin;

        let descripcionFinal = nombre;
        if (desp || org) {
            let extras = [];
            if (desp) extras.push(`Desp: ${desp}`);
            if (org)  extras.push(`Org: ${org}`);
            descripcionFinal += ` (${extras.join(' ')})`;
        }
        return `
        <tr>
            <td>${sku}</td>
            <td>${descripcionFinal}</td>
            <td class="text-center">${item.quantity ?? 1}</td>
            <td class="text-center">u.</td>
            <td class="text-right">${money.format(item.unitPrice || 0)}</td>
            <td class="text-right">${money.format(item.subtotal || 0)}</td>
        </tr>
        `;
    }).join('');
}

const tipoCmp = Number(unificadorNode.CbteTipo || qrNode.tipo_comprobante || 1);
const letras = { 1: 'A', 6: 'B', 11: 'C', 51: 'M' };
const letra = letras[tipoCmp] || 'A'; 
const codigoComprobante = pad(tipoCmp, 3); 

const detalleUni = unificadorNode.detalleParaAfip || {};
const concepto = detalleUni.Concepto || 1; 
const fDesde = formatAfipDate(detalleUni.FchServDesde);
const fHasta = formatAfipDate(detalleUni.FchServHasta);
const fechaEmision = formatAfipDate(detalleUni.CbteFch) || qrNode.fecha_emision;
const fVto = formatAfipDate(detalleUni.FchVtoPago) || fechaEmision;
const caeFinal = String(detAfip.CAE || qrNode.cod_autorizacion || "");
const vtoCaeFinal = formatAfipDate(detAfip.CAEFchVto) || qrNode.vto_cae || ""; 
const qrImg = qrNode.qr_url || "https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=AFIP";

return {
    emisor: emisor,
    cliente: {
        nombre: webhookBody.client.name || "Consumidor Final",       
        cuit: webhookBody.client.cuit || "0",          
        condicionIva: webhookBody.client.tax_condition || webhookBody.client.taxCondition || "Consumidor Final", 
        domicilio: webhookBody.client.address || "-"  
    },
    factura: {
        letra: letra,
        codigo: codigoComprobante,
        ptoVta: pad(qrNode.punto_venta || unificadorNode.PtoVta || 4, 5),      
        numero: pad(detAfip.CbteDesde || qrNode.numero_comprobante || 0, 8), 
        fecha: fechaEmision,              
        vencimiento: fVto,
        concepto: concepto,
        serv_desde: fDesde,
        serv_hasta: fHasta
    },
    totales: {
        subtotal: money.format(webhookBody.totals.subtotal || 0),      
        descuento: money.format(webhookBody.totals.discountAmount || 0), 
        neto: money.format(webhookBody.totals.netTaxable || 0),        
        iva: money.format(webhookBody.totals.vatTotal || 0),
        tasa_iva: tasaIva,
        total: money.format(webhookBody.totals.total || 0),             
        moneda: "$",
    },
    qr: {
        img: qrImg,             
        cae: caeFinal, 
        vto: vtoCaeFinal
    },
    f_asociado: "",
    tabla_productos: itemsHtml 
};
